import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Post, SiteSettings } from './types';
import { INITIAL_POSTS, INITIAL_SETTINGS } from './constants';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Gallery from './components/Gallery';
import NoticeBoard from './components/NoticeBoard';
import Contact from './components/Contact';
import Footer from './components/Footer';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Unlock } from 'lucide-react';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [settings, setSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);

  // Persistence (Simulated)
  useEffect(() => {
    const savedSettings = localStorage.getItem('kkumttre_settings');
    const savedPosts = localStorage.getItem('kkumttre_posts');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    if (savedPosts) setPosts(JSON.parse(savedPosts));
  }, []);

  const updateSettings = (newSettings: SiteSettings) => {
    setSettings(newSettings);
    localStorage.setItem('kkumttre_settings', JSON.stringify(newSettings));
  };

  const addPost = (post: Post) => {
    const updatedPosts = [post, ...posts];
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  const deletePost = (id: string) => {
    const updatedPosts = posts.filter(p => p.id !== id);
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  return (
    <div className="min-h-screen selection:bg-purple-500 selection:text-white">
      <Navbar isAdmin={isAdmin} />

      <main className="space-y-0">
        <Hero settings={settings} />
        <About settings={settings} />
        <Gallery posts={posts.filter(p => p.category === 'ACTIVITY')} />
        <NoticeBoard posts={posts.filter(p => p.category === 'NOTICE')} />
        <Contact settings={settings} />
      </main>

      <Footer settings={settings} />

      {/* Admin Toggle Button */}
      <button
        onClick={() => setIsAdmin(!isAdmin)}
        className="fixed bottom-6 right-6 z-50 p-4 rounded-full glass border-purple-500/30 hover:scale-110 transition-transform shadow-2xl group"
        title={isAdmin ? "관리자 모드 종료" : "관리자 모드 실행"}
      >
        {isAdmin ? (
          <Unlock className="w-6 h-6 text-purple-400" />
        ) : (
          <Lock className="w-6 h-6 text-gray-400 group-hover:text-purple-400" />
        )}
      </button>

      {/* Admin Panel Overlay */}
      {isAdmin && (
        <AdminDashboard 
          settings={settings} 
          updateSettings={updateSettings} 
          posts={posts}
          addPost={addPost}
          deletePost={deletePost}
          onClose={() => setIsAdmin(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Menu, X, Share2 } from 'lucide-react';

interface NavbarProps {
  isAdmin: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ isAdmin }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { name: '소개', href: '#about' },
    { name: '활동 갤러리', href: '#gallery' },
    { name: '공지사항', href: '#notices' },
    { name: '문의하기', href: '#contact' },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-40 transition-all duration-300 ${isScrolled ? 'py-4 glass' : 'py-8 bg-transparent'}`}>
      <div className="container mx-auto px-6 flex items-center justify-between">
        <div className="flex items-center space-x-2">
          <div className="w-10 h-10 purple-gradient rounded-xl flex items-center justify-center font-bold text-white text-xl">
            꿈
          </div>
          <span className="text-xl font-bold tracking-tight">꿈뜨레</span>
          {isAdmin && <span className="ml-2 text-[10px] uppercase tracking-widest bg-purple-500/20 text-purple-400 px-2 py-0.5 rounded-full border border-purple-500/30">ADMIN</span>}
        </div>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center space-x-12">
          {navItems.map((item) => (
            <a 
              key={item.name} 
              href={item.href} 
              className="text-sm font-medium text-gray-400 hover:text-white transition-colors"
            >
              {item.name}
            </a>
          ))}
          <button className="p-2 hover:bg-white/5 rounded-full transition-colors">
            <Share2 className="w-5 h-5 text-gray-300" />
          </button>
        </div>

        {/* Mobile Toggle */}
        <button 
          className="md:hidden p-2 text-gray-300"
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          {mobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="md:hidden fixed inset-0 top-[88px] glass z-50 p-6 flex flex-col space-y-8 animate-in fade-in slide-in-from-top-4 duration-300">
          {navItems.map((item) => (
            <a 
              key={item.name} 
              href={item.href} 
              className="text-2xl font-bold"
              onClick={() => setMobileMenuOpen(false)}
            >
              {item.name}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
};

