interface AdminDashboardProps {
  settings: SiteSettings;
  updateSettings: (s: SiteSettings) => void;
  posts: Post[];
  addPost: (p: Post) => void;
  deletePost: (id: string) => void;
  onClose: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  settings, updateSettings, posts, addPost, deletePost, onClose 
}) => {
  const [activeTab, setActiveTab] = useState<'settings' | 'posts'>('settings');
  const [localSettings, setLocalSettings] = useState<SiteSettings>(settings);

  // New post form state
  const [newPost, setNewPost] = useState<{
    title: string;
    content: string;
    category: PostCategory;
    imageUrl: string;
  }>({
    title: '',
    content: '',
    category: 'NOTICE',
    imageUrl: ''
  });

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    alert('설정이 저장되었습니다.');
  };

  const handleAddPost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPost.title || !newPost.content) return;

    addPost({
      id: Date.now().toString(),
      title: newPost.title,
      content: newPost.content,
      category: newPost.category,
      imageUrl: newPost.category === 'ACTIVITY' ? (newPost.imageUrl || `https://picsum.photos/seed/${Date.now()}/800/600`) : undefined,
      date: new Date().toISOString().split('T')[0]
    });

    setNewPost({ title: '', content: '', category: 'NOTICE', imageUrl: '' });
    alert('새 글이 등록되었습니다.');
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in duration-300">
      <div className="bg-[#111] border border-white/10 w-full max-w-5xl h-full max-h-[90vh] rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl">
        {/* Admin Header */}
        <div className="p-8 border-b border-white/10 flex items-center justify-between bg-white/5">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-purple-500 rounded-lg">
              <Settings className="text-white w-6 h-6" />
            </div>
            <div>
              <h2 className="text-2xl font-bold">꿈뜨레 CMS 관리자 패널</h2>
              <p className="text-xs text-gray-500 tracking-widest uppercase">Content Management System v1.0</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <X className="w-8 h-8" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
