interface AdminDashboardProps {
  settings: SiteSettings;
  updateSettings: (s: SiteSettings) => void;
  posts: Post[];
  addPost: (p: Post) => void;
  deletePost: (id: string) => void;
  onClose: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  settings, updateSettings, posts, addPost, deletePost, onClose 
}) => {
  const [activeTab, setActiveTab] = useState<'settings' | 'posts'>('settings');
  const [localSettings, setLocalSettings] = useState<SiteSettings>(settings);

  // New post form state
  const [newPost, setNewPost] = useState<{
    title: string;
    content: string;
    category: PostCategory;
    imageUrl: string;
  }>({
    title: '',
    content: '',
    category: 'NOTICE',
    imageUrl: ''
  });

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    alert('설정이 저장되었습니다.');
  };

  const handleAddPost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPost.title || !newPost.content) return;

    addPost({
      id: Date.now().toString(),
      title: newPost.title,
      content: newPost.content,
      category: newPost.category,
      imageUrl: newPost.category === 'ACTIVITY' ? (newPost.imageUrl || `https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?auto=format&fit=crop&q=80&w=800`) : undefined,
      date: new Date().toISOString().split('T')[0]
    });

    setNewPost({ title: '', content: '', category: 'NOTICE', imageUrl: '' });
    alert('새 글이 등록되었습니다.');
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in duration-500">
      <div className="bg-[#0a0a0a] border border-white/5 w-full max-w-6xl h-full max-h-[92vh] rounded-[3rem] flex flex-col overflow-hidden shadow-[0_0_100px_rgba(var(--primary-purple-rgb),0.1)]">
        {/* Admin Header */}
        <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-purple-500/20 rounded-2xl border border-purple-500/30">
              <Settings className="text-purple-400 w-6 h-6" />
