import React, { useState, useEffect } from 'react';
import { Post, SiteSettings, PostCategory } from './types';
import { INITIAL_POSTS, INITIAL_SETTINGS } from './constants';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Gallery from './components/Gallery';
import NoticeBoard from './components/NoticeBoard';
import Sponsorship from './components/Sponsorship';
import Contact from './components/Contact';
import Footer from './components/Footer';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Unlock, ArrowRight } from 'lucide-react';

type View = 'HOME' | 'ABOUT' | 'GALLERY' | 'NOTICES' | 'SPONSORSHIP' | 'CONTACT';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [showAdminDashboard, setShowAdminDashboard] = useState(false);
  const [adminDefaultCategory, setAdminDefaultCategory] = useState<PostCategory>('NOTICE');
  const [settings, setSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [currentView, setCurrentView] = useState<View>('HOME');

  useEffect(() => {
    const savedSettings = localStorage.getItem('kkumttre_settings');
    const savedPosts = localStorage.getItem('kkumttre_posts');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    if (savedPosts) setPosts(JSON.parse(savedPosts));
  }, []);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentView]);

  useEffect(() => {
    document.documentElement.style.setProperty('--primary-purple', settings.primaryColor);
    document.documentElement.style.setProperty('--theme-brightness', (settings.themeBrightness / 100).toString());
    const hex = settings.primaryColor.replace('#', '');
    const r = parseInt(hex.substring(0, 2), 16);
    const g = parseInt(hex.substring(2, 4), 16);
    const b = parseInt(hex.substring(4, 6), 16);
    if (!isNaN(r)) {
      document.documentElement.style.setProperty('--primary-purple-rgb', `${r}, ${g}, ${b}`);
    }
  }, [settings]);

  const updateSettings = (newSettings: SiteSettings) => {
    setSettings(newSettings);
    localStorage.setItem('kkumttre_settings', JSON.stringify(newSettings));
  };

  const addPost = (post: Post) => {
    const updatedPosts = [post, ...posts];
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  const deletePost = (id: string) => {
    const updatedPosts = posts.filter(p => p.id !== id);
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  const handleAdminToggle = () => {
    if (isAdmin) {
      setAdminDefaultCategory('NOTICE');
      setShowAdminDashboard(true);
    } else {
      setIsAdmin(true);
    }
  };

  const openAdminWithCategory = (category: PostCategory) => {
    setAdminDefaultCategory(category);
    setShowAdminDashboard(true);
  };

  const renderView = () => {
    switch (currentView) {
      case 'HOME':
        return (
          <>
            <Hero settings={settings} />
            <section className="py-24 bg-white/30">
              <div className="container mx-auto px-6">
                <div className="grid md:grid-cols-2 gap-12">
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-purple-900">최근 공지사항</h4>
                    <div className="space-y-4 mb-8">
                      {posts.filter(p => p.category === 'NOTICE').slice(0, 3).map(p => (
                        <div key={p.id} className="flex justify-between items-center border-b border-purple-50 pb-2">
                          <span className="font-bold text-gray-800 truncate pr-4">{p.title}</span>
                          <span className="text-xs text-purple-400 font-black">{p.date}</span>
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'NOTICE').length === 0 && (
                        <p className="text-sm text-gray-400">등록된 공지사항이 없습니다.</p>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('NOTICES')} className="flex items-center text-sm font-black text-purple-900 hover:translate-x-2 transition-transform">
                      공지사항 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-[#111111]">활동 갤러리</h4>
                    <div className="grid grid-cols-2 gap-4 mb-8">
                      {posts.filter(p => p.category === 'ACTIVITY').slice(0, 2).map(p => (
                        <div key={p.id} className="aspect-square rounded-2xl overflow-hidden">
                          <img src={p.imageUrls?.[0]} className="w-full h-full object-cover" />
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'ACTIVITY').length === 0 && (
                        <div className="col-span-2 h-32 flex items-center justify-center text-sm text-gray-400 border border-dashed border-gray-200 rounded-2xl">
                          등록된 활동이 없습니다.
                        </div>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('GALLERY')} className="flex items-center text-sm font-black text-black hover:translate-x-2 transition-transform">
                      활동기록 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            </section>
          </>
        );
      case 'ABOUT':
        return <About settings={settings} />;
      case 'GALLERY':
        return (
          <Gallery 
            posts={posts.filter(p => p.category === 'ACTIVITY')} 
            isAdmin={isAdmin}
            onWrite={() => openAdminWithCategory('ACTIVITY')}
          />
        );
      case 'NOTICES':
        return (
          <NoticeBoard 
            posts={posts.filter(p => p.category === 'NOTICE')} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('NOTICE')} 
          />
        );
      case 'SPONSORSHIP':
        return (
          <Sponsorship 
            posts={posts.filter(p => p.category === 'SPONSORSHIP')} 
            settings={settings} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('SPONSORSHIP')} 
          />
        );
      case 'CONTACT':
        return <Contact settings={settings} />;
      default:
        return <Hero settings={settings} />;
    }
  };

  return (
    <div className="min-h-screen selection:bg-purple-200 selection:text-purple-900 overflow-x-hidden bg-[#FAF5FF] text-[#111111]">
      <Navbar isAdmin={isAdmin} currentView={currentView} setView={setCurrentView} />

      <main className="min-h-[80vh]">
        {renderView()}
      </main>

      <Footer settings={settings} />

      <button
        onClick={handleAdminToggle}
        className="fixed bottom-6 right-6 z-50 p-4 rounded-full glass border-purple-300 hover:scale-110 transition-transform shadow-2xl group bg-white/80"
        title={isAdmin ? "관리자 대시보드 열기" : "관리자 모드 활성화"}
      >
        {isAdmin ? (
          <Unlock className="w-6 h-6 text-purple-600" />
        ) : (
          <Lock className="w-6 h-6 text-purple-400 group-hover:text-purple-600" />
        )}
      </button>

      {isAdmin && showAdminDashboard && (
        <AdminDashboard 
          settings={settings} 
          updateSettings={updateSettings} 
          posts={posts}
          addPost={addPost}
          deletePost={deletePost}
          onClose={() => setShowAdminDashboard(false)}
          initialCategory={adminDefaultCategory}
        />
      )}
    </div>
  );
};

export default App;

