                          )}
                        </label>
                        <div className="flex items-center text-[9px] text-purple-400 font-black bg-purple-900/20 px-3 py-1 rounded-full border border-purple-900/30">
                          <Info className="w-3 h-3 mr-1" /> 사진 URL을 줄바꿈(Enter)으로 구분하여 여러 장 입력하세요.
                        </div>
                      </div>
                      <div className="relative">
                        <textarea 
                          value={newPost.imageUrls} 
                          onChange={(e) => setNewPost({...newPost, imageUrls: e.target.value})} 
                          className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none text-[11px] focus:border-purple-500 text-purple-200 min-h-[150px] font-mono leading-relaxed placeholder:opacity-30" 
                          placeholder="https://images.unsplash.com/photo-1.jpg&#10;https://images.unsplash.com/photo-2.jpg" 
                        />
                        {currentImagesCount > 0 && (
                          <div className="absolute bottom-4 right-4 animate-bounce">
                            <CheckCircle2 className="w-6 h-6 text-green-500" />
                          </div>
                        )}
                      </div>
                    </div>

                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">상세 내용</label>
                      <textarea required value={newPost.content} onChange={(e) => setNewPost({...newPost, content: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[250px] focus:border-purple-500 text-white leading-relaxed" placeholder="전달하고자 하는 활동 내용이나 공지 사항을 상세히 적어주세요." />
                    </div>

                    <button type="submit" className="w-full md:w-auto bg-purple-600 text-white px-16 py-5 rounded-2xl font-black shadow-2xl hover:bg-purple-700 transition-all flex items-center justify-center space-x-3 active:scale-95 group">
                      <ImageIcon className="w-5 h-5 group-hover:rotate-12 transition-transform" />
                      <span>최종 발행하기</span>
