import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Newspaper, ExternalLink, RefreshCcw, Search, Calendar } from 'lucide-react';

interface NewsItem {
  title: string;
  uri: string;
  source: string;
  snippet?: string;
}

const MediaFeed: React.FC = () => {
  const [news, setNews] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchMedia = async () => {
    setLoading(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "창원시 '꿈뜨레 지역공동체'와 관련된 최신 소식 및 '이한기 칼럼'이나 관련 뉴스를 네이버와 다음 포털을 중심으로 검색해서 알려주세요.",
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      // Extract Grounding Chunks (URLs)
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const extractedNews: NewsItem[] = chunks
        .filter((chunk: any) => chunk.web && chunk.web.uri)
        .map((chunk: any) => ({
          title: chunk.web.title || "관련 뉴스 기사",
          uri: chunk.web.uri,
          source: chunk.web.uri.includes('naver.com') ? '네이버 뉴스' : 
                  chunk.web.uri.includes('daum.net') ? '다음 뉴스' : '언론보도',
          snippet: response.text // Using general response as context
        }));

      // If no chunks, try to parse from text (fallback)
      if (extractedNews.length === 0) {
        setNews([]);
      } else {
        // Limit to top 6 unique results
        const uniqueNews = Array.from(new Set(extractedNews.map(a => a.uri)))
          .map(uri => extractedNews.find(a => a.uri === uri)!)
          .slice(0, 6);
        setNews(uniqueNews);
      }
    } catch (err) {
      console.error(err);
      setError("최신 뉴스를 가져오는 중 오류가 발생했습니다.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMedia();
  }, []);

  return (
    <section className="pt-40 pb-32 bg-white/30 min-h-screen">
      <div className="container mx-auto px-6">
        <div className="flex flex-col md:flex-row justify-between items-end mb-20 gap-8">
          <div className="max-w-2xl">
            <h2 className="text-[10px] uppercase tracking-[0.4em] text-purple-900 font-black mb-4">Media & Columns</h2>
            <h3 className="text-4xl md:text-5xl font-black text-purple-950 mb-8">언론보도 및 이한기 칼럼</h3>
            <p className="text-gray-600 font-medium leading-relaxed">
              네이버, 다음 등 주요 포털 사이트에 게재된 꿈뜨레 지역공동체의 활동 소식과 <span className="text-purple-900 font-bold">이한기 칼럼</span>을 실시간으로 확인하실 수 있습니다.
            </p>
          </div>
          <button 
            onClick={fetchMedia}
            disabled={loading}
            className="flex items-center space-x-3 bg-purple-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-black transition-all shadow-2xl disabled:opacity-50 group"
          >
            <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : 'group-hover:rotate-180 transition-transform'}`} />
            <span>최신 소식 새로고침</span>
          </button>
        </div>

        {loading ? (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => (
              <div key={i} className="glass h-80 rounded-[2.5rem] animate-pulse bg-white/50 border-purple-50"></div>
            ))}
          </div>
        ) : error ? (
          <div className="glass p-20 text-center rounded-[3rem] border-purple-100">
            <Search className="w-16 h-16 text-purple-200 mx-auto mb-6" />
            <p className="text-gray-400 font-bold">{error}</p>
          </div>
        ) : news.length > 0 ? (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {news.map((item, idx) => (
              <a 
                key={idx} 
                href={item.uri} 
                target="_blank" 
                rel="noopener noreferrer"
                className="group glass p-10 rounded-[2.5rem] border-purple-100 hover:border-purple-600 hover:shadow-2xl transition-all bg-white/80 flex flex-col justify-between"
              >
                <div>
                  <div className="flex items-center justify-between mb-6">
                    <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${
                      item.source === '네이버 뉴스' ? 'bg-green-50 text-green-600 border-green-100' : 
                      item.source === '다음 뉴스' ? 'bg-blue-50 text-blue-600 border-blue-100' : 
                      'bg-purple-50 text-purple-600 border-purple-100'
