                  <h4 className="text-xl font-black text-purple-950 mb-6 leading-tight group-hover:underline decoration-purple-300 underline-offset-8">
                    {item.title}
                  </h4>
                </div>
                <div className="flex items-center justify-between pt-8 border-t border-purple-50">
                  <div className="flex items-center text-[10px] text-gray-400 font-bold">
