  }>({
    title: '',
    content: '',
    category: initialCategory,
    imageUrls: ''
  });

  useEffect(() => {
    if (initialCategory) {
      setNewPost(prev => ({ ...prev, category: initialCategory }));
      setActiveTab('posts');
    }
  }, [initialCategory]);

