interface ContactProps {
  settings: SiteSettings;
}

const Contact: React.FC<ContactProps> = ({ settings }) => {
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    subject: '',
    message: ''
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const { name, phone, subject, message } = formData;

    if (!name || !phone || !subject || !message) {
      alert('모든 필드를 입력해 주세요.');
      return;
    }

    // 이메일 본문 구성
    const emailBody = `성함/단체명: ${name}\n연락처: ${phone}\n\n문의내용:\n${message}`;
    const mailtoLink = `mailto:${settings.contactEmail}?subject=${encodeURIComponent(`[꿈뜨레 홈페이지 문의] ${subject}`)}&body=${encodeURIComponent(emailBody)}`;

    // 이메일 클라이언트 호출
    window.location.href = mailtoLink;
  };

  return (
    <section className="pt-40 pb-32 bg-white/10 min-h-screen">
