                  <Phone className="text-purple-600 w-5 h-5" />
                </div>
                <div>
                  <h4 className="font-black mb-1 text-purple-900">전화 번호</h4>
                  <p className="text-sm text-gray-500">{settings.contactPhone}</p>
                </div>
              </div>

              <div className="flex items-start space-x-4">
