                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">이메일 주소</label>
                      <input type="email" value={localSettings.contactEmail} onChange={(e) => setLocalSettings({...localSettings, contactEmail: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">전화번호</label>
                      <input type="text" value={localSettings.contactPhone} onChange={(e) => setLocalSettings({...localSettings, contactPhone: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">찾아오시는 길 (주소)</label>
                      <input type="text" value={localSettings.contactAddress} onChange={(e) => setLocalSettings({...localSettings, contactAddress: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
