import React, { useState, useEffect } from 'react';
import { Post, SiteSettings, PostCategory, View } from './types';
import { INITIAL_POSTS, INITIAL_SETTINGS } from './constants';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Gallery from './components/Gallery';
import NoticeBoard from './components/NoticeBoard';
import Sponsorship from './components/Sponsorship';
import Contact from './components/Contact';
import Footer from './components/Footer';
import AdminDashboard from './components/AdminDashboard';
import MediaFeed from './components/MediaFeed';
import { Lock, Unlock, ArrowRight, ShieldCheck, X } from 'lucide-react';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [showAdminDashboard, setShowAdminDashboard] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [password, setPassword] = useState('');
  const [adminDefaultCategory, setAdminDefaultCategory] = useState<PostCategory>('NOTICE');
  const [settings, setSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [currentView, setCurrentView] = useState<View>('HOME');

  useEffect(() => {
    const savedSettings = localStorage.getItem('kkumttre_settings');
    const savedPosts = localStorage.getItem('kkumttre_posts');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    if (savedPosts) setPosts(JSON.parse(savedPosts));
  }, []);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentView]);

  useEffect(() => {
    document.documentElement.style.setProperty('--primary-purple', settings.primaryColor);
    document.documentElement.style.setProperty('--theme-brightness', (settings.themeBrightness / 100).toString());
    const hex = settings.primaryColor.replace('#', '');
    const r = parseInt(hex.substring(0, 2), 16);
    const g = parseInt(hex.substring(2, 4), 16);
    const b = parseInt(hex.substring(4, 6), 16);
    if (!isNaN(r)) {
      document.documentElement.style.setProperty('--primary-purple-rgb', `${r}, ${g}, ${b}`);
    }
  }, [settings]);

  const updateSettings = (newSettings: SiteSettings) => {
    setSettings(newSettings);
    localStorage.setItem('kkumttre_settings', JSON.stringify(newSettings));
  };

  const addPost = (post: Post) => {
    const updatedPosts = [post, ...posts];
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  const updatePost = (updatedPost: Post) => {
    const updatedPosts = posts.map(p => p.id === updatedPost.id ? updatedPost : p);
    setPosts(updatedPosts);
    localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
  };

  const deletePost = (id: string) => {
    if (window.confirm('정말로 이 게시물을 삭제하시겠습니까?')) {
      const updatedPosts = posts.filter(p => p.id !== id);
      setPosts(updatedPosts);
      localStorage.setItem('kkumttre_posts', JSON.stringify(updatedPosts));
    }
  };

  const handleAdminToggle = () => {
    if (isAdmin) {
      setAdminDefaultCategory('NOTICE');
      setShowAdminDashboard(true);
    } else {
      setShowAuthModal(true);
    }
  };

  const handleAuthSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (password === '0788') {
      setIsAdmin(true);
      setShowAuthModal(false);
      setPassword('');
      setAdminDefaultCategory('NOTICE');
      setShowAdminDashboard(true);
    } else {
      alert("비밀번호가 일치하지 않습니다.");
      setPassword('');
    }
  };

  const openAdminWithCategory = (category: PostCategory) => {
    setAdminDefaultCategory(category);
    setShowAdminDashboard(true);
  };

  const renderView = () => {
    switch (currentView) {
      case 'HOME':
        return (
          <>
            <Hero settings={settings} />
            <section className="py-24 bg-white/30">
              <div className="container mx-auto px-6">
                <div className="grid md:grid-cols-2 gap-12">
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-purple-900">최근 공지사항</h4>
                    <div className="space-y-4 mb-8">
                      {posts.filter(p => p.category === 'NOTICE').slice(0, 3).map(p => (
                        <div key={p.id} className="flex justify-between items-center border-b border-purple-50 pb-2">
                          <span className="font-bold text-gray-800 truncate pr-4">{p.title}</span>
                          <span className="text-xs text-purple-400 font-black">{p.date}</span>
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'NOTICE').length === 0 && (
                        <p className="text-sm text-gray-400">등록된 공지사항이 없습니다.</p>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('NOTICES')} className="flex items-center text-sm font-black text-purple-900 hover:translate-x-2 transition-transform">
                      공지사항 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-[#111111]">활동 갤러리</h4>
                    <div className="grid grid-cols-2 gap-4 mb-8">
                      {posts.filter(p => p.category === 'ACTIVITY').slice(0, 2).map(p => (
                        <div key={p.id} className="aspect-square rounded-2xl overflow-hidden">
                          <img src={p.imageUrls?.[0]} className="w-full h-full object-cover" />
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'ACTIVITY').length === 0 && (
                        <div className="col-span-2 h-32 flex items-center justify-center text-sm text-gray-400 border border-dashed border-gray-200 rounded-2xl">
                          등록된 활동이 없습니다.
                        </div>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('GALLERY')} className="flex items-center text-sm font-black text-black hover:translate-x-2 transition-transform">
                      활동기록 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            </section>
          </>
        );
      case 'ABOUT':
        return <About settings={settings} />;
      case 'GALLERY':
        return (
          <Gallery 
            posts={posts.filter(p => p.category === 'ACTIVITY')} 
            isAdmin={isAdmin}
            onWrite={() => openAdminWithCategory('ACTIVITY')}
            onAddPost={addPost}
          />
        );
      case 'NOTICES':
        return (
          <NoticeBoard 
            posts={posts.filter(p => p.category === 'NOTICE')} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('NOTICE')} 
          />
        );
      case 'SPONSORSHIP':
        return (
          <Sponsorship 
            posts={posts.filter(p => p.category === 'SPONSORSHIP')} 
            settings={settings} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('SPONSORSHIP')} 
          />
        );
      case 'MEDIA':
        return <MediaFeed settings={settings} />;
      case 'CONTACT':
        return <Contact settings={settings} />;
      default:
        return <Hero settings={settings} />;
    }
  };

  return (
    <div className="min-h-screen selection:bg-purple-200 selection:text-purple-900 overflow-x-hidden bg-[#FAF5FF] text-[#111111]">
      <Navbar isAdmin={isAdmin} currentView={currentView} setView={setCurrentView} />

      <main className="min-h-[80vh]">
        {renderView()}
      </main>

      <Footer settings={settings} />

      {/* Admin Auth Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 z-[120] bg-black/60 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] border border-purple-100 shadow-2xl w-full max-w-md p-10 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-purple-900 rounded-xl flex items-center justify-center">
                  <ShieldCheck className="text-white w-6 h-6" />
                </div>
                <h3 className="text-xl font-black text-purple-900 tracking-tight">관리자 인증</h3>
              </div>
              <button onClick={() => setShowAuthModal(false)} className="text-gray-400 hover:text-black">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleAuthSubmit}>
              <p className="text-sm text-gray-500 mb-6 font-medium">관리자 모드 접속을 위해 비밀번호를 입력해 주세요.</p>
              <input 
                autoFocus
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Password"
                className="w-full bg-purple-50 border border-purple-100 rounded-2xl px-6 py-4 outline-none focus:border-purple-600 font-bold mb-6 text-center text-2xl tracking-[0.5em]"
              />
              <button 
                type="submit"
                className="w-full bg-purple-900 text-white py-4 rounded-2xl font-black hover:bg-black transition-all shadow-lg active:scale-95"
              >
                인증 및 확인
              </button>
            </form>
          </div>
        </div>
      )}

      <button
        onClick={handleAdminToggle}
        className="fixed bottom-6 right-6 z-50 p-4 rounded-full glass border-purple-300 hover:scale-110 transition-transform shadow-2xl group bg-white/80"
        title={isAdmin ? "관리자 대시보드 열기" : "관리자 모드 활성화"}
      >
        {isAdmin ? (
          <Unlock className="w-6 h-6 text-purple-600" />
        ) : (
          <Lock className="w-6 h-6 text-purple-400 group-hover:text-purple-600" />
        )}
      </button>

      {isAdmin && showAdminDashboard && (
        <AdminDashboard 
          settings={settings} 
          updateSettings={updateSettings} 
          posts={posts}
          addPost={addPost}
          updatePost={updatePost}
          deletePost={deletePost}
          onClose={() => setShowAdminDashboard(false)}
          initialCategory={adminDefaultCategory}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { SiteSettings, Post, PostCategory, SponsorshipAccount } from '../types';
import { X, Plus, Trash2, Layout, FileText, Settings, User, Palette, Image as ImageIcon, Info, CreditCard, CheckCircle2, Link as LinkIcon, Upload, MapPin, Phone, Mail, Loader2, Edit3, RotateCcw } from 'lucide-react';

interface AdminDashboardProps {
  settings: SiteSettings;
  updateSettings: (s: SiteSettings) => void;
  posts: Post[];
  addPost: (p: Post) => void;
  updatePost: (p: Post) => void;
  deletePost: (id: string) => void;
  onClose: () => void;
  initialCategory?: PostCategory;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  settings, updateSettings, posts, addPost, updatePost, deletePost, onClose, initialCategory = 'NOTICE'
}) => {
  const [activeTab, setActiveTab] = useState<'settings' | 'posts'>(initialCategory ? 'posts' : 'settings');
  const [localSettings, setLocalSettings] = useState<SiteSettings>(settings);

  // 수정 중인 게시글 ID (null이면 새 글 작성 모드)
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  const [newPost, setNewPost] = useState<{
    title: string;
    content: string;
    category: PostCategory;
    imageUrls: string;
  }>({
    title: '',
    content: '',
    category: initialCategory,
    imageUrls: ''
  });

  const [uploadedPostImages, setUploadedPostImages] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);

  const fileInput7Ref = useRef<HTMLInputElement>(null);
  const fileInput3Ref = useRef<HTMLInputElement>(null);
  const fileInputPostRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialCategory) {
      setNewPost(prev => ({ ...prev, category: initialCategory }));
      setActiveTab('posts');
    }
  }, [initialCategory]);

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    alert('설정이 저장되었습니다.');
  };

  const handleAccountChange = (index: number, field: keyof SponsorshipAccount, value: string) => {
    const updatedAccounts = [...localSettings.sponsorshipAccounts];
    updatedAccounts[index] = { ...updatedAccounts[index], [field]: value };
    setLocalSettings({ ...localSettings, sponsorshipAccounts: updatedAccounts });
  };

  const handleCoverImageUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'blogImage7' | 'blogImage3') => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLocalSettings({ ...localSettings, [target]: reader.result as string });
    };
    reader.readAsDataURL(file);
  };

  const handlePostImagesUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const fileArray = Array.from(files);
    setIsUploading(true);

    const promises = fileArray.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          resolve(reader.result as string);
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(promises).then(base64Images => {
      setUploadedPostImages(prev => [...prev, ...base64Images]);
      setIsUploading(false);
    });
  };

  const removeUploadedImage = (index: number) => {
    setUploadedPostImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleEditClick = (post: Post) => {
    setEditingPostId(post.id);
    setNewPost({
      title: post.title,
      content: post.content,
      category: post.category,
      imageUrls: post.imageUrls ? post.imageUrls.filter(url => !url.startsWith('data:image')).join('\n') : ''
    });
    setUploadedPostImages(post.imageUrls ? post.imageUrls.filter(url => url.startsWith('data:image')) : []);

    // 폼으로 스크롤
    document.querySelector('.custom-scrollbar')?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingPostId(null);
    setNewPost({ title: '', content: '', category: initialCategory, imageUrls: '' });
    setUploadedPostImages([]);
  };

  const handleSubmitPost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPost.title || !newPost.content) return;

    const urlFromInput = newPost.imageUrls
      .split(/[\n,]/)
      .map(url => url.trim())
      .filter(url => url !== '');

    const finalImageUrls = [...uploadedPostImages, ...urlFromInput];

    if (editingPostId) {
      // 수정 모드
      const originalPost = posts.find(p => p.id === editingPostId);
      updatePost({
        ...originalPost!,
        title: newPost.title,
        content: newPost.content,
        category: newPost.category,
        imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
      });
      alert('게시물이 수정되었습니다.');
    } else {
      // 새 글 작성 모드
      addPost({
        id: Date.now().toString(),
        title: newPost.title,
        content: newPost.content,
        category: newPost.category,
        imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
        date: new Date().toISOString().split('T')[0]
      });
      alert('새 콘텐츠가 성공적으로 발행되었습니다.');
    }

    handleCancelEdit();
  };

  const totalImagesCount = uploadedPostImages.length + newPost.imageUrls
    .split(/[\n,]/)
    .map(url => url.trim())
    .filter(url => url !== '').length;

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in duration-500">
      <div className="bg-[#0a0a0a] border border-white/5 w-full max-w-6xl h-full max-h-[92vh] rounded-[3rem] flex flex-col overflow-hidden shadow-2xl">
        <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
          <div className="flex items-center space-x-4">
            <div className="w-10 h-10 bg-purple-600 rounded-xl flex items-center justify-center">
              <Settings className="text-white w-6 h-6" />
            </div>
            <h2 className="text-2xl font-black text-white">꿈뜨레 CMS 마스터</h2>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/5 rounded-full transition-all group">
            <X className="w-8 h-8 text-gray-400 group-hover:text-white group-hover:rotate-90 transition-all" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 border-r border-white/5 p-8 flex flex-col space-y-3 bg-white/[0.01]">
            <button 
              onClick={() => setActiveTab('settings')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'settings' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <Layout className="w-5 h-5" />
              <span className="font-bold">기본 사이트 제어</span>
            </button>
            <button 
              onClick={() => setActiveTab('posts')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'posts' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <FileText className="w-5 h-5" />
              <span className="font-bold">발행 콘텐츠 관리</span>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-12 custom-scrollbar bg-black/40">
            {activeTab === 'settings' ? (
              <div className="space-y-12 max-w-4xl">
                {/* 대표자 및 단체 정보 */}
                <section className="space-y-8">
                  <div className="flex items-center space-x-3 mb-6">
                    <User className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">대표자 및 단체 기본정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표자 이름</label>
                      <input type="text" value={localSettings.representativeName} onChange={(e) => setLocalSettings({...localSettings, representativeName: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표 인사말</label>
                      <textarea value={localSettings.representativeGreeting} onChange={(e) => setLocalSettings({...localSettings, representativeGreeting: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[100px] text-white" />
                    </div>
                  </div>
                </section>

                {/* 연락처 및 위치 정보 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <Mail className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">연락처 및 위치 정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">이메일 주소</label>
                      <input type="email" value={localSettings.contactEmail} onChange={(e) => setLocalSettings({...localSettings, contactEmail: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">전화번호</label>
                      <input type="text" value={localSettings.contactPhone} onChange={(e) => setLocalSettings({...localSettings, contactPhone: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">찾아오시는 길 (주소)</label>
                      <input type="text" value={localSettings.contactAddress} onChange={(e) => setLocalSettings({...localSettings, contactAddress: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                  </div>
                </section>

                {/* 공식 채널 및 표지 사진 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <LinkIcon className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">공식 채널 및 표지 사진 관리</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-10">
                    <div className="p-8 rounded-[2.5rem] bg-white/[0.03] border border-white/5 space-y-8">
                      <div className="flex items-center justify-between">
                        <h4 className="text-sm font-black text-purple-400">7호점 설정</h4>
                        <div className="w-12 h-12 rounded-2xl overflow-hidden border border-white/10">
                           <img src={localSettings.blogImage7} className="w-full h-full object-cover" />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">블로그 연결 주소</label>
                        <input type="url" value={localSettings.blogUrl7} onChange={(e) => setLocalSettings({...localSettings, blogUrl7: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-purple-200 text-xs" />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">표지 사진 첨부 (JPG/PNG)</label>
                        <input type="file" accept="image/*" ref={fileInput7Ref} onChange={(e) => handleCoverImageUpload(e, 'blogImage7')} className="hidden" />
                        <button onClick={() => fileInput7Ref.current?.click()} className="w-full flex items-center justify-center space-x-3 bg-white/5 border border-dashed border-white/20 rounded-xl py-4 hover:bg-white/10 hover:border-purple-500 transition-all group">
                          <Upload className="w-4 h-4 text-gray-500 group-hover:text-purple-400" />
                          <span className="text-[11px] font-black text-gray-400 group-hover:text-white">파일에서 사진 선택하기</span>
                        </button>
                      </div>
                    </div>

                    <div className="p-8 rounded-[2.5rem] bg-white/[0.03] border border-white/5 space-y-8">
                      <div className="flex items-center justify-between">
                        <h4 className="text-sm font-black text-purple-400">3호점 설정</h4>
                        <div className="w-12 h-12 rounded-2xl overflow-hidden border border-white/10">
                           <img src={localSettings.blogImage3} className="w-full h-full object-cover" />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">블로그 연결 주소</label>
                        <input type="url" value={localSettings.blogUrl3} onChange={(e) => setLocalSettings({...localSettings, blogUrl3: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-purple-200 text-xs" />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">표지 사진 첨부 (JPG/PNG)</label>
                        <input type="file" accept="image/*" ref={fileInput3Ref} onChange={(e) => handleCoverImageUpload(e, 'blogImage3')} className="hidden" />
                        <button onClick={() => fileInput3Ref.current?.click()} className="w-full flex items-center justify-center space-x-3 bg-white/5 border border-dashed border-white/20 rounded-xl py-4 hover:bg-white/10 hover:border-purple-500 transition-all group">
                          <Upload className="w-4 h-4 text-gray-500 group-hover:text-purple-400" />
                          <span className="text-[11px] font-black text-gray-400 group-hover:text-white">파일에서 사진 선택하기</span>
                        </button>
                      </div>
                    </div>
                  </div>
                </section>

                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <CreditCard className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">후원 계좌 관리</h3>
                  </div>
                  <div className="space-y-10">
                    {localSettings.sponsorshipAccounts.map((account, index) => (
                      <div key={index} className="p-6 rounded-3xl bg-white/[0.03] border border-white/5 space-y-4">
                        <h4 className="text-sm font-black text-purple-400">계좌 {index + 1}</h4>
                        <div className="grid md:grid-cols-3 gap-6">
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">은행명</label>
                            <input type="text" value={account.bankName} onChange={(e) => handleAccountChange(index, 'bankName', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">계좌번호</label>
                            <input type="text" value={account.accountNumber} onChange={(e) => handleAccountChange(index, 'accountNumber', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">예금주</label>
                            <input type="text" value={account.accountHolder} onChange={(e) => handleAccountChange(index, 'accountHolder', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>

                <button onClick={handleSaveSettings} className="bg-white text-black px-12 py-5 rounded-[1.5rem] font-black hover:bg-purple-600 hover:text-white transition-all shadow-xl">설정 저장하기</button>
              </div>
            ) : (
              <div className="space-y-16 max-w-4xl">
                <div className={`glass p-10 rounded-[2.5rem] border-white/10 transition-all ${editingPostId ? 'bg-purple-900/10 border-purple-500/30' : 'bg-white/[0.03]'}`}>
                  <div className="flex items-center justify-between mb-10">
                    <h4 className="text-2xl font-black flex items-center italic text-white underline decoration-purple-600 underline-offset-8">
                      {editingPostId ? <Edit3 className="mr-3 text-purple-400 w-8 h-8" /> : <Plus className="mr-3 text-purple-400 w-8 h-8" />}
                      {editingPostId ? '게시물 수정 중...' : 
                       newPost.category === 'ACTIVITY' ? '새로운 활동 기록하기' : 
                       newPost.category === 'NOTICE' ? '새로운 공지 발행하기' : '새로운 후원소식 발행하기'}
                    </h4>
                    {editingPostId && (
                      <button 
                        onClick={handleCancelEdit}
                        className="flex items-center space-x-2 text-xs font-black text-gray-400 hover:text-white bg-white/5 px-4 py-2 rounded-xl transition-all"
                      >
                        <RotateCcw className="w-3.5 h-3.5" />
                        <span>수정 취소</span>
                      </button>
                    )}
                  </div>

                  <form onSubmit={handleSubmitPost} className="space-y-10">
                    <div className="grid md:grid-cols-3 gap-8">
                      <div className="md:col-span-2">
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">글 제목</label>
                        <input type="text" required value={newPost.title} onChange={(e) => setNewPost({...newPost, title: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold text-lg" placeholder="제목을 입력하세요." />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">카테고리</label>
                        <select value={newPost.category} onChange={(e) => setNewPost({...newPost, category: e.target.value as PostCategory})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none text-white font-bold cursor-pointer focus:border-purple-500">
                          <option value="ACTIVITY">활동 갤러리 (Activity)</option>
                          <option value="NOTICE">공지사항 (Notice)</option>
                          <option value="SPONSORSHIP">후원소식 (Sponsorship)</option>
                        </select>
                      </div>
                    </div>

                    <div className="space-y-8">
                      <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest flex items-center">
                          <ImageIcon className="w-3 h-3 mr-2 text-purple-400" />
                          사진 파일 첨부 (JPG/PNG)
                        </label>
                        <input 
                          type="file" 
                          multiple 
                          accept="image/*" 
                          ref={fileInputPostRef} 
                          onChange={handlePostImagesUpload}
                          className="hidden" 
                        />
                        <button 
                          type="button"
                          onClick={() => fileInputPostRef.current?.click()}
                          className="w-full flex items-center justify-center space-x-3 bg-white/5 border border-dashed border-white/20 rounded-2xl py-8 hover:bg-white/10 hover:border-purple-500 transition-all group"
                        >
                          {isUploading ? (
                            <Loader2 className="w-6 h-6 text-purple-500 animate-spin" />
                          ) : (
                            <>
                              <Upload className="w-6 h-6 text-gray-500 group-hover:text-purple-400" />
                              <div className="text-left">
                                <p className="text-[12px] font-black text-white">컴퓨터에서 사진 선택하기</p>
                                <p className="text-[10px] text-gray-500">여러 장을 동시에 선택할 수 있습니다.</p>
                              </div>
                            </>
                          )}
                        </button>
                      </div>

                      {uploadedPostImages.length > 0 && (
                        <div className="grid grid-cols-4 md:grid-cols-6 gap-4 p-4 bg-white/5 rounded-2xl border border-white/5">
                          {uploadedPostImages.map((img, idx) => (
                            <div key={idx} className="relative aspect-square group">
                              <img src={img} className="w-full h-full object-cover rounded-xl border border-white/10" />
                              <button 
                                type="button"
                                onClick={() => removeUploadedImage(idx)}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                              >
                                <X className="w-3 h-3" />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}

                      <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest flex items-center">
                          <LinkIcon className="w-3 h-3 mr-2 text-purple-400" />
                          또는 웹 이미지 URL 입력
                        </label>
                        <textarea 
                          value={newPost.imageUrls} 
                          onChange={(e) => setNewPost({...newPost, imageUrls: e.target.value})} 
                          className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none text-[11px] focus:border-purple-500 text-purple-200 min-h-[80px] font-mono leading-relaxed" 
                          placeholder="https://example.com/photo.jpg (엔터로 구분)" 
                        />
                      </div>
                    </div>

                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">상세 내용</label>
                      <textarea required value={newPost.content} onChange={(e) => setNewPost({...newPost, content: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[200px] focus:border-purple-500 text-white leading-relaxed" placeholder="전달하고자 하는 내용을 상세히 적어주세요." />
                    </div>

                    <button type="submit" className={`w-full md:w-auto px-16 py-5 rounded-2xl font-black shadow-2xl transition-all flex items-center justify-center space-x-3 active:scale-95 group ${editingPostId ? 'bg-blue-600 hover:bg-blue-700 text-white' : 'bg-purple-600 hover:bg-purple-700 text-white'}`}>
                      {editingPostId ? <CheckCircle2 className="w-5 h-5 group-hover:scale-110" /> : <Plus className="w-5 h-5 group-hover:rotate-90" />}
                      <span>{editingPostId ? '수정 사항 저장하기' : `${totalImagesCount}장의 사진과 함께 발행하기`}</span>
                    </button>
                  </form>
                </div>

                <div className="space-y-8">
                  <h4 className="text-2xl font-black text-white flex items-center">
                    <FileText className="mr-3 text-purple-500" />
                    전체 발행 목록 ({posts.length})
                  </h4>
                  <div className="grid gap-4">
                    {posts.map(post => (
                      <div key={post.id} className={`flex items-center justify-between p-6 glass rounded-2xl border-white/5 group hover:bg-white/[0.06] transition-all ${editingPostId === post.id ? 'bg-purple-600/20 border-purple-500/50' : 'bg-white/[0.02]'}`}>
                        <div className="flex items-center space-x-5">
                          <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${
                            post.category === 'NOTICE' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 
                            post.category === 'ACTIVITY' ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' : 
                            'bg-pink-500/10 text-pink-400 border-pink-500/20'
                          }`}>
                            {post.category}
                          </span>
                          <div>
                            <h5 className="font-bold text-white group-hover:text-purple-400 transition-colors line-clamp-1">{post.title}</h5>
                            <p className="text-[10px] text-gray-500 mt-1">{post.date} • {post.imageUrls?.length || 0} Photos</p>
                          </div>
                        </div>
                        <div className="flex items-center space-x-2">
                          <button 
                            onClick={() => handleEditClick(post)}
                            className="p-3 text-gray-500 hover:text-blue-400 transition-all opacity-0 group-hover:opacity-100 hover:bg-blue-400/10 rounded-xl"
                            title="게시물 수정"
                          >
                            <Edit3 className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => deletePost(post.id)} 
                            className="p-3 text-gray-500 hover:text-red-500 transition-all opacity-0 group-hover:opacity-100 hover:bg-red-500/10 rounded-xl"
                            title="게시물 삭제"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    ))}
                    {posts.length === 0 && (
                      <div className="py-20 text-center text-gray-500 border border-dashed border-white/10 rounded-[2.5rem]">
                        발행된 콘텐츠가 아직 없습니다.
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Post, SiteSettings, PostCategory, View } from './types';
import { INITIAL_POSTS, INITIAL_SETTINGS } from './constants';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Gallery from './components/Gallery';
import NoticeBoard from './components/NoticeBoard';
import Sponsorship from './components/Sponsorship';
import Contact from './components/Contact';
import Footer from './components/Footer';
import AdminDashboard from './components/AdminDashboard';
import MediaFeed from './components/MediaFeed';
import { Lock, Unlock, ArrowRight, ShieldCheck, X } from 'lucide-react';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [showAdminDashboard, setShowAdminDashboard] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [password, setPassword] = useState('');
  const [adminDefaultCategory, setAdminDefaultCategory] = useState<PostCategory>('NOTICE');
  const [settings, setSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [currentView, setCurrentView] = useState<View>('HOME');

  useEffect(() => {
    const savedSettings = localStorage.getItem('kkumttre_settings');
    const savedPosts = localStorage.getItem('kkumttre_posts');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    if (savedPosts) setPosts(JSON.parse(savedPosts));
  }, []);

  // posts가 변경될 때마다 로컬 스토리지 자동 저장
  useEffect(() => {
    if (posts.length > 0 || localStorage.getItem('kkumttre_posts')) {
      localStorage.setItem('kkumttre_posts', JSON.stringify(posts));
    }
  }, [posts]);

  useEffect(() => {
    document.documentElement.style.setProperty('--primary-purple', settings.primaryColor);
    document.documentElement.style.setProperty('--theme-brightness', (settings.themeBrightness / 100).toString());
    const hex = settings.primaryColor.replace('#', '');
    const r = parseInt(hex.substring(0, 2), 16);
    const g = parseInt(hex.substring(2, 4), 16);
    const b = parseInt(hex.substring(4, 6), 16);
    if (!isNaN(r)) {
      document.documentElement.style.setProperty('--primary-purple-rgb', `${r}, ${g}, ${b}`);
    }
  }, [settings]);

  const updateSettings = (newSettings: SiteSettings) => {
    setSettings(newSettings);
    localStorage.setItem('kkumttre_settings', JSON.stringify(newSettings));
  };

  const addPost = (post: Post) => {
    setPosts(prev => [post, ...prev]);
  };

  const updatePost = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  const deletePost = (id: string) => {
    if (window.confirm('정말로 이 게시물을 삭제하시겠습니까?')) {
      setPosts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleAdminToggle = () => {
    if (isAdmin) {
      setAdminDefaultCategory('NOTICE');
      setShowAdminDashboard(true);
    } else {
      setShowAuthModal(true);
    }
  };

  const handleAuthSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (password === '0788') {
      setIsAdmin(true);
      setShowAuthModal(false);
      setPassword('');
      setAdminDefaultCategory('NOTICE');
      setShowAdminDashboard(true);
    } else {
      alert("비밀번호가 일치하지 않습니다.");
      setPassword('');
    }
  };

  const openAdminWithCategory = (category: PostCategory) => {
    setAdminDefaultCategory(category);
    setShowAdminDashboard(true);
  };

  const renderView = () => {
    switch (currentView) {
      case 'HOME':
        return (
          <>
            <Hero settings={settings} />
            <section className="py-24 bg-white/30">
              <div className="container mx-auto px-6">
                <div className="grid md:grid-cols-2 gap-12">
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-purple-900">최근 공지사항</h4>
                    <div className="space-y-4 mb-8">
                      {posts.filter(p => p.category === 'NOTICE').slice(0, 3).map(p => (
                        <div key={p.id} className="flex justify-between items-center border-b border-purple-50 pb-2">
                          <span className="font-bold text-gray-800 truncate pr-4">{p.title}</span>
                          <span className="text-xs text-purple-400 font-black">{p.date}</span>
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'NOTICE').length === 0 && (
                        <p className="text-sm text-gray-400">등록된 공지사항이 없습니다.</p>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('NOTICES')} className="flex items-center text-sm font-black text-purple-900 hover:translate-x-2 transition-transform">
                      공지사항 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                  <div className="glass p-10 rounded-[2.5rem] border-purple-100/50 hover:shadow-2xl transition-all">
                    <h4 className="text-2xl font-black mb-4 text-[#111111]">활동 갤러리</h4>
                    <div className="grid grid-cols-2 gap-4 mb-8">
                      {posts.filter(p => p.category === 'ACTIVITY').slice(0, 2).map(p => (
                        <div key={p.id} className="aspect-square rounded-2xl overflow-hidden">
                          <img src={p.imageUrls?.[0]} className="w-full h-full object-cover" />
                        </div>
                      ))}
                      {posts.filter(p => p.category === 'ACTIVITY').length === 0 && (
                        <div className="col-span-2 h-32 flex items-center justify-center text-sm text-gray-400 border border-dashed border-gray-200 rounded-2xl">
                          등록된 활동이 없습니다.
                        </div>
                      )}
                    </div>
                    <button onClick={() => setCurrentView('GALLERY')} className="flex items-center text-sm font-black text-black hover:translate-x-2 transition-transform">
                      활동기록 더보기 <ArrowRight className="ml-2 w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            </section>
          </>
        );
      case 'ABOUT':
        return <About settings={settings} />;
      case 'GALLERY':
        return (
          <Gallery 
            posts={posts.filter(p => p.category === 'ACTIVITY')} 
            isAdmin={isAdmin}
            onWrite={() => openAdminWithCategory('ACTIVITY')}
            onAddPost={addPost}
          />
        );
      case 'NOTICES':
        return (
          <NoticeBoard 
            posts={posts.filter(p => p.category === 'NOTICE')} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('NOTICE')} 
          />
        );
      case 'SPONSORSHIP':
        return (
          <Sponsorship 
            posts={posts.filter(p => p.category === 'SPONSORSHIP')} 
            settings={settings} 
            isAdmin={isAdmin} 
            onWrite={() => openAdminWithCategory('SPONSORSHIP')} 
          />
        );
      case 'MEDIA':
        return <MediaFeed settings={settings} />;
      case 'CONTACT':
        return <Contact settings={settings} />;
      default:
        return <Hero settings={settings} />;
    }
  };

  return (
    <div className="min-h-screen selection:bg-purple-200 selection:text-purple-900 overflow-x-hidden bg-[#FAF5FF] text-[#111111]">
      <Navbar isAdmin={isAdmin} currentView={currentView} setView={setCurrentView} />

      <main className="min-h-[80vh]">
        {renderView()}
      </main>

      <Footer settings={settings} />

      {/* Admin Auth Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 z-[120] bg-black/60 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] border border-purple-100 shadow-2xl w-full max-w-md p-10 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-purple-900 rounded-xl flex items-center justify-center">
                  <ShieldCheck className="text-white w-6 h-6" />
                </div>
                <h3 className="text-xl font-black text-purple-900 tracking-tight">관리자 인증</h3>
              </div>
              <button onClick={() => setShowAuthModal(false)} className="text-gray-400 hover:text-black">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleAuthSubmit}>
              <p className="text-sm text-gray-500 mb-6 font-medium">관리자 모드 접속을 위해 비밀번호를 입력해 주세요.</p>
              <input 
                autoFocus
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Password"
                className="w-full bg-purple-50 border border-purple-100 rounded-2xl px-6 py-4 outline-none focus:border-purple-600 font-bold mb-6 text-center text-2xl tracking-[0.5em]"
              />
              <button 
                type="submit"
                className="w-full bg-purple-900 text-white py-4 rounded-2xl font-black hover:bg-black transition-all shadow-lg active:scale-95"
              >
                인증 및 확인
              </button>
            </form>
          </div>
        </div>
      )}

      <button
        onClick={handleAdminToggle}
        className="fixed bottom-6 right-6 z-50 p-4 rounded-full glass border-purple-300 hover:scale-110 transition-transform shadow-2xl group bg-white/80"
        title={isAdmin ? "관리자 대시보드 열기" : "관리자 모드 활성화"}
      >
        {isAdmin ? (
          <Unlock className="w-6 h-6 text-purple-600" />
        ) : (
          <Lock className="w-6 h-6 text-purple-400 group-hover:text-purple-600" />
        )}
      </button>

      {isAdmin && showAdminDashboard && (
        <AdminDashboard 
          settings={settings} 
          updateSettings={updateSettings} 
          posts={posts}
          addPost={addPost}
          updatePost={updatePost}
          deletePost={deletePost}
          onClose={() => setShowAdminDashboard(false)}
          initialCategory={adminDefaultCategory}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { SiteSettings, Post, PostCategory, SponsorshipAccount } from '../types';
import { X, Plus, Trash2, Layout, FileText, Settings, User, Palette, Image as ImageIcon, Info, CreditCard, CheckCircle2, Link as LinkIcon, Upload, MapPin, Phone, Mail, Loader2, Edit3, RotateCcw } from 'lucide-react';

interface AdminDashboardProps {
  settings: SiteSettings;
  updateSettings: (s: SiteSettings) => void;
  posts: Post[];
  addPost: (p: Post) => void;
  updatePost: (p: Post) => void;
  deletePost: (id: string) => void;
  onClose: () => void;
  initialCategory?: PostCategory;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  settings, updateSettings, posts, addPost, updatePost, deletePost, onClose, initialCategory = 'NOTICE'
}) => {
  const [activeTab, setActiveTab] = useState<'settings' | 'posts'>(initialCategory ? 'posts' : 'settings');
  const [localSettings, setLocalSettings] = useState<SiteSettings>(settings);

  // 수정 중인 게시글 ID (null이면 새 글 작성 모드)
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  const [newPost, setNewPost] = useState<{
    title: string;
    content: string;
    category: PostCategory;
    imageUrls: string;
  }>({
    title: '',
    content: '',
    category: initialCategory,
    imageUrls: ''
  });

  const [uploadedPostImages, setUploadedPostImages] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);

  const fileInput7Ref = useRef<HTMLInputElement>(null);
  const fileInput3Ref = useRef<HTMLInputElement>(null);
  const fileInputPostRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialCategory) {
      setNewPost(prev => ({ ...prev, category: initialCategory }));
      setActiveTab('posts');
    }
  }, [initialCategory]);

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    alert('설정이 저장되었습니다.');
  };

  const handleAccountChange = (index: number, field: keyof SponsorshipAccount, value: string) => {
    const updatedAccounts = [...localSettings.sponsorshipAccounts];
    updatedAccounts[index] = { ...updatedAccounts[index], [field]: value };
    setLocalSettings({ ...localSettings, sponsorshipAccounts: updatedAccounts });
  };

  const handleCoverImageUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'blogImage7' | 'blogImage3') => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLocalSettings({ ...localSettings, [target]: reader.result as string });
    };
    reader.readAsDataURL(file);
  };

  const handlePostImagesUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const fileArray = Array.from(files);
    setIsUploading(true);

    const promises = fileArray.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          resolve(reader.result as string);
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(promises).then(base64Images => {
      setUploadedPostImages(prev => [...prev, ...base64Images]);
      setIsUploading(false);
    });
  };

  const removeUploadedImage = (index: number) => {
    setUploadedPostImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleEditClick = (e: React.MouseEvent, post: Post) => {
    e.stopPropagation();
    setEditingPostId(post.id);
    setNewPost({
      title: post.title,
      content: post.content,
      category: post.category,
      imageUrls: post.imageUrls ? post.imageUrls.filter(url => !url.startsWith('data:image')).join('\n') : ''
    });
    setUploadedPostImages(post.imageUrls ? post.imageUrls.filter(url => url.startsWith('data:image')) : []);

    // 폼으로 부드럽게 스크롤
    document.querySelector('.custom-scrollbar')?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingPostId(null);
    setNewPost({ title: '', content: '', category: initialCategory, imageUrls: '' });
    setUploadedPostImages([]);
  };

  const handleSubmitPost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPost.title || !newPost.content) return;

    const urlFromInput = newPost.imageUrls
      .split(/[\n,]/)
      .map(url => url.trim())
      .filter(url => url !== '');

    const finalImageUrls = [...uploadedPostImages, ...urlFromInput];

    if (editingPostId) {
      // 수정 모드
      const originalPost = posts.find(p => p.id === editingPostId);
      if (originalPost) {
        updatePost({
          ...originalPost,
          title: newPost.title,
          content: newPost.content,
          category: newPost.category,
          imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
        });
        alert('게시물이 수정되었습니다.');
      }
    } else {
      // 새 글 작성 모드
      addPost({
        id: Date.now().toString(),
        title: newPost.title,
        content: newPost.content,
        category: newPost.category,
        imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
        date: new Date().toISOString().split('T')[0]
      });
      alert('새 콘텐츠가 성공적으로 발행되었습니다.');
    }

    handleCancelEdit();
  };

  const handleDeletePost = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    deletePost(id);
  };

  const totalImagesCount = uploadedPostImages.length + newPost.imageUrls
    .split(/[\n,]/)
    .map(url => url.trim())
    .filter(url => url !== '').length;

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in duration-500">
      <div className="bg-[#0a0a0a] border border-white/5 w-full max-w-6xl h-full max-h-[92vh] rounded-[3rem] flex flex-col overflow-hidden shadow-2xl">
        <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
          <div className="flex items-center space-x-4">
            <div className="w-10 h-10 bg-purple-600 rounded-xl flex items-center justify-center">
              <Settings className="text-white w-6 h-6" />
            </div>
            <h2 className="text-2xl font-black text-white">꿈뜨레 CMS 마스터</h2>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/5 rounded-full transition-all group">
            <X className="w-8 h-8 text-gray-400 group-hover:text-white group-hover:rotate-90 transition-all" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 border-r border-white/5 p-8 flex flex-col space-y-3 bg-white/[0.01]">
            <button 
              onClick={() => setActiveTab('settings')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'settings' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <Layout className="w-5 h-5" />
              <span className="font-bold">기본 사이트 제어</span>
            </button>
            <button 
              onClick={() => setActiveTab('posts')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'posts' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <FileText className="w-5 h-5" />
              <span className="font-bold">발행 콘텐츠 관리</span>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-12 custom-scrollbar bg-black/40">
            {activeTab === 'settings' ? (
              <div className="space-y-12 max-w-4xl">
                {/* 기본 정보 설정 */}
                <section className="space-y-8">
                  <div className="flex items-center space-x-3 mb-6">
                    <User className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">대표자 및 단체 기본정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표자 이름</label>
                      <input type="text" value={localSettings.representativeName} onChange={(e) => setLocalSettings({...localSettings, representativeName: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표 인사말</label>
                      <textarea value={localSettings.representativeGreeting} onChange={(e) => setLocalSettings({...localSettings, representativeGreeting: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[100px] text-white" />
                    </div>
                  </div>
                </section>

                {/* 연락처 설정 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <Mail className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">연락처 및 위치 정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">이메일 주소</label>
                      <input type="email" value={localSettings.contactEmail} onChange={(e) => setLocalSettings({...localSettings, contactEmail: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">전화번호</label>
                      <input type="text" value={localSettings.contactPhone} onChange={(e) => setLocalSettings({...localSettings, contactPhone: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">찾아오시는 길 (주소)</label>
                      <input type="text" value={localSettings.contactAddress} onChange={(e) => setLocalSettings({...localSettings, contactAddress: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                  </div>
                </section>

                {/* 후원 계좌 등 나머지 설정 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <CreditCard className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">후원 계좌 관리</h3>
                  </div>
                  <div className="space-y-10">
                    {localSettings.sponsorshipAccounts.map((account, index) => (
                      <div key={index} className="p-6 rounded-3xl bg-white/[0.03] border border-white/5 space-y-4">
                        <h4 className="text-sm font-black text-purple-400">계좌 {index + 1}</h4>
                        <div className="grid md:grid-cols-3 gap-6">
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">은행명</label>
                            <input type="text" value={account.bankName} onChange={(e) => handleAccountChange(index, 'bankName', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">계좌번호</label>
                            <input type="text" value={account.accountNumber} onChange={(e) => handleAccountChange(index, 'accountNumber', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">예금주</label>
                            <input type="text" value={account.accountHolder} onChange={(e) => handleAccountChange(index, 'accountHolder', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>

                <button onClick={handleSaveSettings} className="bg-white text-black px-12 py-5 rounded-[1.5rem] font-black hover:bg-purple-600 hover:text-white transition-all shadow-xl">설정 저장하기</button>
              </div>
            ) : (
              <div className="space-y-16 max-w-4xl">
                {/* 콘텐츠 발행 폼 */}
                <div className={`glass p-10 rounded-[2.5rem] border-white/10 transition-all ${editingPostId ? 'bg-purple-900/10 border-purple-500/30' : 'bg-white/[0.03]'}`}>
                  <div className="flex items-center justify-between mb-10">
                    <h4 className="text-2xl font-black flex items-center italic text-white underline decoration-purple-600 underline-offset-8">
                      {editingPostId ? <Edit3 className="mr-3 text-purple-400 w-8 h-8" /> : <Plus className="mr-3 text-purple-400 w-8 h-8" />}
                      {editingPostId ? '게시물 수정 중...' : 
                       newPost.category === 'ACTIVITY' ? '새로운 활동 기록하기' : 
                       newPost.category === 'NOTICE' ? '새로운 공지 발행하기' : '새로운 후원소식 발행하기'}
                    </h4>
                    {editingPostId && (
                      <button 
                        onClick={handleCancelEdit}
                        className="flex items-center space-x-2 text-xs font-black text-gray-400 hover:text-white bg-white/5 px-4 py-2 rounded-xl transition-all"
                      >
                        <RotateCcw className="w-3.5 h-3.5" />
                        <span>수정 취소</span>
                      </button>
                    )}
                  </div>

                  <form onSubmit={handleSubmitPost} className="space-y-10">
                    <div className="grid md:grid-cols-3 gap-8">
                      <div className="md:col-span-2">
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">글 제목</label>
                        <input type="text" required value={newPost.title} onChange={(e) => setNewPost({...newPost, title: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold text-lg" placeholder="제목을 입력하세요." />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">카테고리</label>
                        <select value={newPost.category} onChange={(e) => setNewPost({...newPost, category: e.target.value as PostCategory})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none text-white font-bold cursor-pointer focus:border-purple-500">
                          <option value="ACTIVITY">활동 갤러리 (Activity)</option>
                          <option value="NOTICE">공지사항 (Notice)</option>
                          <option value="SPONSORSHIP">후원소식 (Sponsorship)</option>
                        </select>
                      </div>
                    </div>

                    <div className="space-y-8">
                      <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest flex items-center">
                          <ImageIcon className="w-3 h-3 mr-2 text-purple-400" />
                          사진 파일 첨부 (JPG/PNG)
                        </label>
                        <input 
                          type="file" 
                          multiple 
                          accept="image/*" 
                          ref={fileInputPostRef} 
                          onChange={handlePostImagesUpload}
                          className="hidden" 
                        />
                        <button 
                          type="button"
                          onClick={() => fileInputPostRef.current?.click()}
                          className="w-full flex items-center justify-center space-x-3 bg-white/5 border border-dashed border-white/20 rounded-2xl py-8 hover:bg-white/10 hover:border-purple-500 transition-all group"
                        >
                          {isUploading ? (
                            <Loader2 className="w-6 h-6 text-purple-500 animate-spin" />
                          ) : (
                            <>
                              <Upload className="w-6 h-6 text-gray-500 group-hover:text-purple-400" />
                              <div className="text-left">
                                <p className="text-[12px] font-black text-white">컴퓨터에서 사진 선택하기</p>
                                <p className="text-[10px] text-gray-500">여러 장을 동시에 선택할 수 있습니다.</p>
                              </div>
                            </>
                          )}
                        </button>
                      </div>

                      {uploadedPostImages.length > 0 && (
                        <div className="grid grid-cols-4 md:grid-cols-6 gap-4 p-4 bg-white/5 rounded-2xl border border-white/5">
                          {uploadedPostImages.map((img, idx) => (
                            <div key={idx} className="relative aspect-square group">
                              <img src={img} className="w-full h-full object-cover rounded-xl border border-white/10" />
                              <button 
                                type="button"
                                onClick={() => removeUploadedImage(idx)}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg transition-all"
                              >
                                <X className="w-3 h-3" />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>

                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">상세 내용</label>
                      <textarea required value={newPost.content} onChange={(e) => setNewPost({...newPost, content: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[200px] focus:border-purple-500 text-white leading-relaxed" placeholder="전달하고자 하는 내용을 상세히 적어주세요." />
                    </div>

                    <button type="submit" className={`w-full md:w-auto px-16 py-5 rounded-2xl font-black shadow-2xl transition-all flex items-center justify-center space-x-3 active:scale-95 group ${editingPostId ? 'bg-blue-600 hover:bg-blue-700 text-white' : 'bg-purple-600 hover:bg-purple-700 text-white'}`}>
                      {editingPostId ? <CheckCircle2 className="w-5 h-5 group-hover:scale-110" /> : <Plus className="w-5 h-5 group-hover:rotate-90" />}
                      <span>{editingPostId ? '수정 사항 저장하기' : `${totalImagesCount}장의 사진과 함께 발행하기`}</span>
                    </button>
                  </form>
                </div>

                {/* 발행 목록 (수정/삭제 버튼 포함) */}
                <div className="space-y-8">
                  <h4 className="text-2xl font-black text-white flex items-center">
                    <FileText className="mr-3 text-purple-500" />
                    전체 발행 목록 ({posts.length})
                  </h4>
                  <div className="grid gap-4">
                    {posts.map(post => (
                      <div 
                        key={post.id} 
                        className={`flex items-center justify-between p-6 glass rounded-2xl border-white/5 group hover:bg-white/[0.06] transition-all ${editingPostId === post.id ? 'bg-purple-600/20 border-purple-500/50' : 'bg-white/[0.02]'}`}
                      >
                        <div className="flex items-center space-x-5">
                          <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${
                            post.category === 'NOTICE' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 
                            post.category === 'ACTIVITY' ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' : 
                            'bg-pink-500/10 text-pink-400 border-pink-500/20'
                          }`}>
                            {post.category}
                          </span>
                          <div>
                            <h5 className="font-bold text-white group-hover:text-purple-400 transition-colors line-clamp-1">{post.title}</h5>
                            <p className="text-[10px] text-gray-500 mt-1">{post.date} • {post.imageUrls?.length || 0} Photos</p>
                          </div>
                        </div>
                        <div className="flex items-center space-x-2">
                          <button 
                            onClick={(e) => handleEditClick(e, post)}
                            className="p-3 text-blue-400 hover:text-white hover:bg-blue-400/20 rounded-xl transition-all md:opacity-0 md:group-hover:opacity-100"
                            title="수정하기"
                          >
                            <Edit3 className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={(e) => handleDeletePost(e, post.id)} 
                            className="p-3 text-red-400 hover:text-white hover:bg-red-400/20 rounded-xl transition-all md:opacity-0 md:group-hover:opacity-100"
                            title="삭제하기"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    ))}
                    {posts.length === 0 && (
                      <div className="py-20 text-center text-gray-500 border border-dashed border-white/10 rounded-[2.5rem]">
                        발행된 콘텐츠가 아직 없습니다.
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { SiteSettings, Post, PostCategory, SponsorshipAccount } from '../types';
import { X, Plus, Trash2, Layout, FileText, Settings, User, Palette, Image as ImageIcon, Info, CreditCard, CheckCircle2, Link as LinkIcon, Upload, MapPin, Phone, Mail, Loader2, Edit3, RotateCcw } from 'lucide-react';

interface AdminDashboardProps {
  settings: SiteSettings;
  updateSettings: (s: SiteSettings) => void;
  posts: Post[];
  addPost: (p: Post) => void;
  updatePost: (p: Post) => void;
  deletePost: (id: string) => void;
  onClose: () => void;
  initialCategory?: PostCategory;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  settings, updateSettings, posts, addPost, updatePost, deletePost, onClose, initialCategory = 'NOTICE'
}) => {
  const [activeTab, setActiveTab] = useState<'settings' | 'posts'>(initialCategory ? 'posts' : 'settings');
  const [localSettings, setLocalSettings] = useState<SiteSettings>(settings);

  // 수정 중인 게시글 ID (null이면 새 글 작성 모드)
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  const [newPost, setNewPost] = useState<{
    title: string;
    content: string;
    category: PostCategory;
    imageUrls: string;
  }>({
    title: '',
    content: '',
    category: initialCategory,
    imageUrls: ''
  });

  const [uploadedPostImages, setUploadedPostImages] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);

  const fileInput7Ref = useRef<HTMLInputElement>(null);
  const fileInput3Ref = useRef<HTMLInputElement>(null);
  const fileInputPostRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialCategory) {
      setNewPost(prev => ({ ...prev, category: initialCategory }));
      setActiveTab('posts');
    }
  }, [initialCategory]);

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    alert('설정이 저장되었습니다.');
  };

  const handleAccountChange = (index: number, field: keyof SponsorshipAccount, value: string) => {
    const updatedAccounts = [...localSettings.sponsorshipAccounts];
    updatedAccounts[index] = { ...updatedAccounts[index], [field]: value };
    setLocalSettings({ ...localSettings, sponsorshipAccounts: updatedAccounts });
  };

  const handleCoverImageUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'blogImage7' | 'blogImage3') => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLocalSettings({ ...localSettings, [target]: reader.result as string });
    };
    reader.readAsDataURL(file);
  };

  const handlePostImagesUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const fileArray = Array.from(files);
    setIsUploading(true);

    const promises = fileArray.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          resolve(reader.result as string);
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(promises).then(base64Images => {
      setUploadedPostImages(prev => [...prev, ...base64Images]);
      setIsUploading(false);
    });
  };

  const removeUploadedImage = (index: number) => {
    setUploadedPostImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleEditClick = (e: React.MouseEvent, post: Post) => {
    e.stopPropagation();
    setEditingPostId(post.id);
    setNewPost({
      title: post.title,
      content: post.content,
      category: post.category,
      imageUrls: post.imageUrls ? post.imageUrls.filter(url => !url.startsWith('data:image')).join('\n') : ''
    });
    setUploadedPostImages(post.imageUrls ? post.imageUrls.filter(url => url.startsWith('data:image')) : []);

    // 폼으로 부드럽게 스크롤
    document.querySelector('.custom-scrollbar')?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingPostId(null);
    setNewPost({ title: '', content: '', category: initialCategory, imageUrls: '' });
    setUploadedPostImages([]);
  };

  const handleSubmitPost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPost.title || !newPost.content) return;

    const urlFromInput = newPost.imageUrls
      .split(/[\n,]/)
      .map(url => url.trim())
      .filter(url => url !== '');

    const finalImageUrls = [...uploadedPostImages, ...urlFromInput];

    if (editingPostId) {
      // 수정 모드
      const originalPost = posts.find(p => p.id === editingPostId);
      if (originalPost) {
        updatePost({
          ...originalPost,
          title: newPost.title,
          content: newPost.content,
          category: newPost.category,
          imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
        });
        alert('게시물이 수정되었습니다.');
      }
    } else {
      // 새 글 작성 모드
      addPost({
        id: Date.now().toString(),
        title: newPost.title,
        content: newPost.content,
        category: newPost.category,
        imageUrls: finalImageUrls.length > 0 ? finalImageUrls : undefined,
        date: new Date().toISOString().split('T')[0]
      });
      alert('새 콘텐츠가 성공적으로 발행되었습니다.');
    }

    handleCancelEdit();
  };

  const handleDeletePost = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    deletePost(id);
  };

  const totalImagesCount = uploadedPostImages.length + newPost.imageUrls
    .split(/[\n,]/)
    .map(url => url.trim())
    .filter(url => url !== '').length;

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in duration-500">
      <div className="bg-[#0a0a0a] border border-white/5 w-full max-w-6xl h-full max-h-[92vh] rounded-[3rem] flex flex-col overflow-hidden shadow-2xl">
        <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
          <div className="flex items-center space-x-4">
            <div className="w-10 h-10 bg-purple-600 rounded-xl flex items-center justify-center">
              <Settings className="text-white w-6 h-6" />
            </div>
            <h2 className="text-2xl font-black text-white">꿈뜨레 CMS 마스터</h2>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white/5 rounded-full transition-all group">
            <X className="w-8 h-8 text-gray-400 group-hover:text-white group-hover:rotate-90 transition-all" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 border-r border-white/5 p-8 flex flex-col space-y-3 bg-white/[0.01]">
            <button 
              onClick={() => setActiveTab('settings')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'settings' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <Layout className="w-5 h-5" />
              <span className="font-bold">기본 사이트 제어</span>
            </button>
            <button 
              onClick={() => setActiveTab('posts')}
              className={`flex items-center space-x-4 p-5 rounded-[1.5rem] transition-all ${activeTab === 'posts' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
              <FileText className="w-5 h-5" />
              <span className="font-bold">발행 콘텐츠 관리</span>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-12 custom-scrollbar bg-black/40">
            {activeTab === 'settings' ? (
              <div className="space-y-12 max-w-4xl">
                {/* 기본 정보 설정 */}
                <section className="space-y-8">
                  <div className="flex items-center space-x-3 mb-6">
                    <User className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">대표자 및 단체 기본정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표자 이름</label>
                      <input type="text" value={localSettings.representativeName} onChange={(e) => setLocalSettings({...localSettings, representativeName: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">대표 인사말</label>
                      <textarea value={localSettings.representativeGreeting} onChange={(e) => setLocalSettings({...localSettings, representativeGreeting: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none min-h-[100px] text-white" />
                    </div>
                  </div>
                </section>

                {/* 연락처 설정 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <Mail className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">연락처 및 위치 정보</h3>
                  </div>
                  <div className="grid md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">이메일 주소</label>
                      <input type="email" value={localSettings.contactEmail} onChange={(e) => setLocalSettings({...localSettings, contactEmail: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">전화번호</label>
                      <input type="text" value={localSettings.contactPhone} onChange={(e) => setLocalSettings({...localSettings, contactPhone: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-3 tracking-widest">찾아오시는 길 (주소)</label>
                      <input type="text" value={localSettings.contactAddress} onChange={(e) => setLocalSettings({...localSettings, contactAddress: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 text-white font-bold" />
                    </div>
                  </div>
                </section>

                {/* 후원 계좌 등 나머지 설정 */}
                <section className="space-y-8 pt-8 border-t border-white/5">
                  <div className="flex items-center space-x-3 mb-6">
                    <CreditCard className="w-5 h-5 text-purple-400" />
                    <h3 className="text-xl font-bold text-white">후원 계좌 관리</h3>
                  </div>
                  <div className="space-y-10">
                    {localSettings.sponsorshipAccounts.map((account, index) => (
                      <div key={index} className="p-6 rounded-3xl bg-white/[0.03] border border-white/5 space-y-4">
                        <h4 className="text-sm font-black text-purple-400">계좌 {index + 1}</h4>
                        <div className="grid md:grid-cols-3 gap-6">
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">은행명</label>
                            <input type="text" value={account.bankName} onChange={(e) => handleAccountChange(index, 'bankName', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">계좌번호</label>
                            <input type="text" value={account.accountNumber} onChange={(e) => handleAccountChange(index, 'accountNumber', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">예금주</label>
                            <input type="text" value={account.accountHolder} onChange={(e) => handleAccountChange(index, 'accountHolder', e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-purple-500 text-white font-bold text-sm" />
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>

                <button onClick={handleSaveSettings} className="bg-white text-black px-12 py-5 rounded-[1.5rem] font-black hover:bg-purple-600 hover:text-white transition-all shadow-xl">설정 저장하기</button>
              </div>
            ) : (
              <div className="space-y-16 max-w-4xl">
                {/* 콘텐츠 발행 폼 */}
                <div className={`glass p-10 rounded-[2.5rem] border-white/10 transition-all ${editingPostId ? 'bg-purple-900/10 border-purple-500/30' : 'bg-white/[0.03]'}`}>
                  <div className="flex items-center justify-between mb-10">
                    <h4 className="text-2xl font-black flex items-center italic text-white underline decoration-purple-600 underline-offset-8">
                      {editingPostId ? <Edit3 className="mr-3 text-purple-400 w-8 h-8" /> : <Plus className="mr-3 text-purple-400 w-8 h-8" />}
                      {editingPostId ? '게시물 수정 중...' : 
                       newPost.category === 'ACTIVITY' ? '새로운 활동 기록하기' : 
                       newPost.category === 'NOTICE' ? '새로운 공지 발행하기' : '새로운 후원소식 발행하기'}
                    </h4>
                    {editingPostId && (
                      <button 
                        onClick={handleCancelEdit}
                        className="flex items-center space-x-2 text-xs font-black text-gray-400 hover:text-white bg-white/5 px-4 py-2 rounded-xl transition-all"
                      >
                        <RotateCcw className="w-3.5 h-3.5" />
                        <span>수정 취소</span>
                      </button>
                    )}
                  </div>

                  <form onSubmit={handleSubmitPost} className="space-y-10">
                    <div className="grid md:grid-cols-3 gap-8">
                      <div className="md:col-span-2">
